import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { validateUser } from "../../Services/LoginService";
import "../../DisplayView.css";

const LoginPage = () => {
  const navigate = useNavigate();
  const [errors, setErrors] = useState({});
  const [loginData, setLoginData] = useState({ username: "", password: "" });
  const [flag, setFlag] = useState(true);

  const onChangeHandler = (event) => {
    const { name, value } = event.target;
    setFlag(true);
    setLoginData((prev) => ({ ...prev, [name]: value }));
  };

  const validateLogin = () => {
    validateUser(loginData.username, loginData.password)
      .then((response) => {
        const role = String(response.data);
        if (role === "Admin") navigate("/admin-menu");
        else if (role === "Student") navigate("/student-menu");
        else setFlag(false);
      })
      .catch(() => setFlag(false));
  };

  const handleValidation = (event) => {
    event.preventDefault();
    let tempErrors = {};
    let isValid = true;

    if (!loginData.username.trim()) {
      tempErrors.username = "Username is required";
      isValid = false;
    }
    if (!loginData.password.trim()) {
      tempErrors.password = "Password is required";
      isValid = false;
    }

    setErrors(tempErrors);
    if (isValid) validateLogin();
  };

  return (
    <div className="login-wrapper">
      <div className="glass-card">

        {/* ── Header ── */}
        <div className="login-header">
          <div className="av-ring">
            <div className="ring"></div>
            <div className="icon">🔍</div>
          </div>
          <h1 className="main-title">
            <span className="sparkle">✦</span>
            Lost &amp; Found Locator
            <span className="sparkle">✦</span>
          </h1>
          <p>Sign in to your campus account</p>
          <div className="title-underline"></div>
        </div>

        {/* ── Form ── */}
        <form onSubmit={handleValidation}>

          <div className="input-group">
            <label className="input-label">Username</label>
            <input
              type="text"
              placeholder="Enter your username"
              name="username"
              value={loginData.username}
              onChange={onChangeHandler}
              className="modern-input"
            />
            {errors.username && (
              <small className="error-text">{errors.username}</small>
            )}
          </div>

          <div className="input-group">
            <label className="input-label">Password</label>
            <input
              type="password"
              placeholder="••••••••"
              name="password"
              value={loginData.password}
              onChange={onChangeHandler}
              className="modern-input"
            />
            {errors.password && (
              <small className="error-text">{errors.password}</small>
            )}
          </div>

          <button type="submit" className="modern-btn">
            Sign In →
          </button>

        </form>

        {/* ── Auth error ── */}
        {!flag && (
          <p className="error-text center">
            ✕ Invalid username or password
          </p>
        )}

        {/* ── Register link ── */}
        <div className="register-section">
          <span>Don't have an account? </span>
          <button
            className="register-btn-modern"
            onClick={() => navigate("/register")}
          >
            Create Account
          </button>
        </div>

      </div>
    </div>
  );
};

export default LoginPage;
